// Recibir PDF en base64 y separar páginas usando pdftk
const body = $('Webhook').first().json.body;
const pdfBase64 = body.archivo_base64;
const fileName = body.archivo_nombre || 'documento.pdf';
const tipoDoc = body.tipo_documento || 'compra';
const empresaId = body.empresa_id || 0;
const fechaContable = body.fecha_contable || '';

// Guardar PDF temporal
const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const tmpDir = '/tmp/kontia_split_' + Date.now();
fs.mkdirSync(tmpDir, { recursive: true });

const inputPath = path.join(tmpDir, 'input.pdf');
fs.writeFileSync(inputPath, Buffer.from(pdfBase64, 'base64'));

// Separar con pdftk o qpdf
let pages = [];
try {
  // Intentar con qpdf (más común en Docker)
  const pageCount = execSync(`qpdf --show-npages ${inputPath}`).toString().trim();
  const numPages = parseInt(pageCount);

  for (let i = 1; i <= numPages; i++) {
    const outPath = path.join(tmpDir, `page_${i}.pdf`);
    execSync(`qpdf ${inputPath} --pages . ${i} -- ${outPath}`);
    const pageBase64 = fs.readFileSync(outPath).toString('base64');
    pages.push({
      archivo_base64: pageBase64,
      archivo_nombre: fileName.replace('.pdf', `_pag${i}.pdf`),
      media_type: 'application/pdf',
      tipo_documento: tipoDoc,
      empresa_id: empresaId,
      fecha_contable: fechaContable,
      pagina: i,
      total_paginas: numPages
    });
  }
} catch(e) {
  // Si no hay qpdf, devolver el PDF completo sin separar
  pages.push({
    archivo_base64: pdfBase64,
    archivo_nombre: fileName,
    media_type: 'application/pdf',
    tipo_documento: tipoDoc,
    empresa_id: empresaId,
    fecha_contable: fechaContable,
    pagina: 1,
    total_paginas: 1,
    error: 'qpdf no disponible: ' + e.message
  });
}

// Limpiar tmp
try { execSync(`rm -rf ${tmpDir}`); } catch(e) {}

return pages.map(p => ({ json: p }));

